const k = (n) => n * 1000;
const fmt = (n) => "$\u00a0" + new Intl.NumberFormat("es-AR",{maximumFractionDigits:0}).format(n||0);
const pct = (c,p) => p>0 ? Math.round(((p-c)/p)*100) : 0;
const fmtH = (n, hide) => hide ? "$ ****" : fmt(n);

const exportarReporte = (sales, mes) => {
  const grupos = {};
  sales.forEach(function(s) {
    const parts = (s.productName||"Producto").split(" · ");
    const key = parts.slice(0,2).join(" · ");
    if (!grupos[key]) grupos[key] = {ventas:0,qty:0,total:0,ganancia:0};
    grupos[key].ventas++;
    grupos[key].qty += s.qty||1;
    grupos[key].total += s.total||0;
    grupos[key].ganancia += s.profit||0;
  });
  const n = function(v){ return new Intl.NumberFormat("es-AR").format(v||0); };
  const tV = sales.reduce(function(a,s){return a+(s.total||0);},0);
  const tG = sales.reduce(function(a,s){return a+(s.profit||0);},0);
  const doc = document.implementation.createHTMLDocument("Reporte "+mes);
  doc.body.innerHTML = Object.entries(grupos).sort(function(a,b){return b[1].total-a[1].total;}).map(function(e){
    return e[0]+": "+n(e[1].total)+" / gan "+n(e[1].ganancia);
  }).join("\n");
  const blob = new Blob(["Reporte "+mes+"\n\n"+doc.body.innerText], {type:"text/plain;charset=utf-8;"});
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href=url; a.download="reporte-brago-"+mes.toLowerCase().replace(/ /g,"-")+".txt";
  a.click(); URL.revokeObjectURL(url);
};
