const syncSave = async (data) => {
  try {
    await fetch(API, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(data)
    });
  } catch(e) { console.log("sync save error:", e); }
};

const syncLoad = async () => {
  try {
    const resp = await fetch(API);
    if (!resp.ok) return null;
    return await resp.json();
  } catch(e) { return null; }
};
const DIAS = ["Dom","Lun","Mar","Mié","Jue","Vie","Sáb"];
const MESES = ["enero","febrero","marzo","abril","mayo","junio","julio","agosto","septiembre","octubre","noviembre","diciembre"];
const fechaL = function(iso){ if(!iso) return ""; var d=new Date(iso); return DIAS[d.getDay()]+" "+d.getDate()+" de "+MESES[d.getMonth()]; };
const getFeriaNum = (ferias,fecha) => { const d=new Date(fecha); return ferias.filter(f=>{const fd=new Date(f.startDate);return fd.getMonth()===d.getMonth()&&fd.getFullYear()===d.getFullYear();}).length+1; };

