const crearICS = (titulo,fecha,hora,desc) => {
  const d=new Date(fecha);
  const pad=function(n){return String(n).padStart(2,"0");};
  const h=Number(hora.split(":")[0]);
  const ymd=String(d.getFullYear())+pad(d.getMonth()+1)+pad(d.getDate());
  const s=ymd+"T"+pad(h)+"0000";
  const e=ymd+"T"+pad(h+2)+"0000";
  const url="data:text/calendar;charset=utf8,BEGIN:VCALENDAR%0AVERSION:2.0%0ABEGIN:VEVENT%0ADTSTART="+s+"%0ADTEND="+e+"%0ASUMMARY="+encodeURIComponent(titulo)+"%0ADESCRIPTION="+encodeURIComponent(desc)+"%0AEND:VEVENT%0AEND:VCALENDAR";
  const a=document.createElement("a");a.href=url;a.download="brago.ics";a.click();
};

